import{c as e,Q as o,j as a,m as s}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Anthropic Code w/ Claude 2026 Live Blog — @simonw","description":"","frontmatter":{"title":"Anthropic Code w/ Claude 2026 Live Blog — @simonw","author":"Simon Willison（@simonw）","date":"2026-05-06T00:00:00.000Z","source":"https://simonwillison.net/2026/May/6/code-w-claude-2026/","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-06-@simonw-code-w-claude-event.md","filePath":"research/tweets/2026-05-06-@simonw-code-w-claude-event.md","lastUpdated":1779894392000}'),d={name:"research/tweets/2026-05-06-@simonw-code-w-claude-event.md"};function r(n,t,i,l,h,c){return o(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="anthropic-code-w-claude-2026-live-blog-—-simonw" tabindex="-1">Anthropic Code w/ Claude 2026 Live Blog — @simonw <a class="header-anchor" href="#anthropic-code-w-claude-2026-live-blog-—-simonw" aria-label="Permalink to &quot;Anthropic Code w/ Claude 2026 Live Blog — @simonw&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://simonwillison.net/2026/May/6/code-w-claude-2026/" target="_blank" rel="noreferrer">https://simonwillison.net/2026/May/6/code-w-claude-2026/</a><strong>作者</strong>：Simon Willison（@simonw） <strong>發布日期</strong>：2026-05-06 <strong>收錄日期</strong>：2026-05-10 <strong>類型</strong>：推文 + Live Blog 摘要 <strong>分類</strong>：claude-code-tips</p><hr><h2 id="核心推文" tabindex="-1">核心推文 <a class="header-anchor" href="#核心推文" aria-label="Permalink to &quot;核心推文&quot;">​</a></h2><blockquote><p>&quot;Live blogging Anthropic&#39;s Code w/ Claude 2026 event:</p><ul><li>Rate limits doubled for Pro/Max/Enterprise (5-hour → 10-hour Claude Code sessions)</li><li>Claude Code Routines GA — scheduled / webhook-triggered automated tasks</li><li>Expanded MCP support with alwaysLoad:true for permanent tools</li><li>Extension model: skills + sub-agents + hooks + MCP all composable</li></ul><p>Key insight: extensibility is THE differentiator. Model is commodity now.&quot;</p></blockquote><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Anthropic Code w/ Claude 2026 活動的即時記錄。核心訊號：速率限制加倍（session 長度 5h → 10h），Routines GA，MCP alwaysLoad 機制上線。Simon 的核心洞見：<strong>可擴充性（extensibility）是關鍵差異化，模型已成商品</strong>。</p><h3 id="重要功能更新" tabindex="-1">重要功能更新 <a class="header-anchor" href="#重要功能更新" aria-label="Permalink to &quot;重要功能更新&quot;">​</a></h3><table tabindex="0"><thead><tr><th>功能</th><th>變化</th><th>Harness 意涵</th></tr></thead><tbody><tr><td>Session 長度</td><td>5h → 10h</td><td>長任務 harness 需求增加</td></tr><tr><td>Routines GA</td><td>Scheduled + Webhook</td><td>Harness 自動化觸發點增加</td></tr><tr><td><code>alwaysLoad: true</code></td><td>MCP 永久工具常態可見</td><td>Tool context 管理策略改變</td></tr><tr><td>Extension model</td><td>skills + agents + hooks + MCP</td><td>Harness 組合性是設計核心</td></tr></tbody></table><h3 id="simon-的-harness-洞見" tabindex="-1">Simon 的 harness 洞見 <a class="header-anchor" href="#simon-的-harness-洞見" aria-label="Permalink to &quot;Simon 的 harness 洞見&quot;">​</a></h3><blockquote><p>&quot;The model is the commodity. What differentiates teams is the harness they build around it — the skills, the context management, the integration patterns.&quot;</p></blockquote><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>相關性</td><td>9/10</td><td>Anthropic 官方功能更新直接影響 harness 設計</td></tr><tr><td>可行動性</td><td>8/10</td><td><code>alwaysLoad:true</code> + Routines 可立即應用</td></tr><tr><td>新穎性</td><td>7/10</td><td>功能更新報導，非新理論</td></tr><tr><td><strong>總評</strong></td><td><strong>8/10</strong></td><td>—</td></tr></tbody></table><hr><h2 id="與-cc-workspace-的連結" tabindex="-1">與 cc-workspace 的連結 <a class="header-anchor" href="#與-cc-workspace-的連結" aria-label="Permalink to &quot;與 cc-workspace 的連結&quot;">​</a></h2><ul><li><code>research/best-practices/27-whats-new-w18-w19.md</code> 涵蓋相關功能</li><li><code>alwaysLoad: true</code> 影響 context-management.md §Prompt Caching 架構</li><li>Routines GA 與 <code>research/best-practices/11-routines.md</code> 的更新對應</li></ul>',18)])])}const p=e(d,[["render",r]]);export{m as __pageData,p as default};
